export const checkId = 'dynamic-port';
export const name = 'Dynamic Port Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const PORT_ENV_PATTERNS = [
  /process\.env\.PORT\b/,
  /process\.env\['PORT'\]/,
  /process\.env\["PORT"\]/,
  /\benv\.PORT\b/,
  /import\.meta\.env\.PORT\b/,
  /Deno\.env\.get\(['"]PORT['"]\)/,
  /Bun\.env\.PORT\b/,
  /const\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /let\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /var\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /PORT\s*=\s*process\.env/,
  /listen\s*\(\s*(?:process\.env\.PORT|env\.PORT|Deno\.env|Bun\.env|import\.meta\.env\.PORT)/,
];

const HARDCODED_PORT_PATTERNS = [
  /\.listen\s*\(\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /\.listen\s*\(\s*\{[^}]*port\s*:\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
];

const FALLBACK_PORT_PATTERNS = [
  /process\.env\.PORT.*(?:\|\||\?\?)\s*\d+/,
  /(?:Number|parseInt)\s*\(\s*process\.env\.PORT\s*\).*?(?:\|\||\?\?)\s*\d+/,
  /\{\s*PORT\s*=\s*\d+\s*\}\s*=\s*process\.env/,
];

const NON_PROD_PATHS = [
  /(?:^|\/)examples?\//,
  /(?:^|\/)demo\//,
  /(?:^|\/)demos\//,
  /(?:^|\/)test\//,
  /(?:^|\/)__tests__\//,
  /(?:^|\/)spec\//,
  /(?:^|\/)benchmark\//,
  /(?:^|\/)perf\//,
  /(?:^|\/)docs\//,
  /(?:^|\/)fixture\//,
  /(?:^|\/)fixtures\//,
  /(?:^|\/)playground\//,
  /(?:^|\/)playgrounds\//,
  /(?:^|\/)sandbox\//,
  /(?:^|\/)stub\//,
  /(?:^|\/)stubs\//,
  /(?:^|\/)mock\//,
  /(?:^|\/)mocks\//,
  /(?:^|\/)e2e\//,
  /(?:^|\/)cypress\//,
  /(?:^|\/)playwright\//,
  /(?:^|\/)storybook\//,
  /(?:^|\/)stories\//,
  /(?:^|\/)coverage\//,
  /(?:^|\/)jest\//,
  /(?:^|\/)vitest\//,
  /\.github\//,
];

const FRAMEWORK_DEPS = [
  'next', 'nuxt', 'astro', 'remix', 'svelte-kit', 'nitropack', 'nitro', 'nuxi', 'gatsby', 'vite',
];

const SERVER_DEPS = [
  'express', 'fastify', 'koa', 'hono', 'polka', 'restify', 'connect',
  'sirv', 'http-server', 'serve', 'serve-static', 'micro',
];

const HARDCODED_PORT_RE = /\b(?:3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/;

function isNonProductionPath(filePath) {
  return NON_PROD_PATHS.some(p => p.test(filePath));
}

function isFrameworkApp(packageJson) {
  const deps = { ...packageJson?.dependencies, ...packageJson?.devDependencies };
  return FRAMEWORK_DEPS.some(f => deps[f]);
}

function isServerFramework(packageJson) {
  const deps = { ...packageJson?.dependencies, ...packageJson?.devDependencies };
  return SERVER_DEPS.some(f => deps[f]);
}

function isFrameworkSource(tree, packageJson) {
  const hasWorkspaces = !!packageJson?.workspaces || tree.some(p => /^pnpm-workspace\.ya?ml$/.test(p));
  const hasPackages = tree.some(p => /^packages\/[^/]+\//.test(p));
  const hasExamples = tree.some(p => /^(?:examples?|demos?|playground|playgrounds)\//.test(p));
  const hasApps = tree.some(p => /^apps\/[^/]+\//.test(p));
  const isPrivate = packageJson?.private === true;

  if (hasWorkspaces && hasPackages && !hasApps && isPrivate && hasExamples) return true;

  const pkgCount = new Set(tree.filter(p => /^packages\/[^/]+\//.test(p)).map(p => p.split('/')[1])).size;
  const appCount = new Set(tree.filter(p => /^apps\/[^/]+\//.test(p)).map(p => p.split('/')[1])).size;
  if (pkgCount >= 3 && appCount === 0 && hasExamples) return true;

  return false;
}

function looksLikeLibraryOrTool(packageJson, tree) {
  if (!packageJson) return false;

  const name = packageJson.name || '';
  if (name === 'turbo') return true;

  if (isServerFramework(packageJson) || isFrameworkApp(packageJson)) return false;

  const keywords = packageJson.keywords || [];
  const libKeywords = ['library', 'plugin', 'webpack', 'rollup', 'vite-plugin', 'babel', 'parser', 'compiler', 'build-tool', 'cli', 'toolkit', 'monorepo'];
  const hasLibKeyword = keywords.some(k => libKeywords.some(lk => k.toLowerCase().includes(lk)));
  const hasPeerDeps = !!packageJson.peerDependencies;

  if (hasPeerDeps && hasLibKeyword) return true;

  const isMonorepo = packageJson.private === true && !!packageJson.workspaces;
  const hasPackages = tree.some(p => /^packages\//.test(p));
  const hasApps = tree.some(p => /^apps\//.test(p));
  if (isMonorepo && hasPackages && !hasApps && !packageJson.scripts?.start && !packageJson.scripts?.serve) {
    return true;
  }

  const main = packageJson.main || packageJson.module || '';
  if ((main.includes('dist') || main.includes('lib') || main.includes('build')) && !packageJson.scripts?.start && !packageJson.scripts?.serve) {
    return true;
  }

  if (packageJson.bin && !packageJson.scripts?.start && !packageJson.scripts?.serve) return true;

  return false;
}

function looksLikeStaticSite(packageJson, tree) {
  const scripts = packageJson?.scripts || {};
  const allDeps = { ...packageJson?.dependencies, ...packageJson?.devDependencies };

  const serverCommands = /\b(?:node|ts-node|nodemon|pm2|next|nuxt|astro|serve|http-server|nitro|wrangler)\b/;
  const scriptValues = Object.entries(scripts)
    .filter(([k]) => ['start', 'dev', 'serve', 'preview'].includes(k))
    .map(([, v]) => v)
    .join(' ');
  if (serverCommands.test(scriptValues)) return false;

  const hasServerFile = tree.some(p =>
    /(?:^|\/)(?:server|app|index|main)\.(?:js|ts|mjs|cjs)$/.test(p) &&
    !/test|spec|\.d\.ts|node_modules|\/dist\/|\/build\//.test(p)
  );
  if (hasServerFile) return false;

  const staticGenerators = ['astro', 'next', 'nuxt', 'gatsby', 'vitepress', 'docusaurus'];
  const hasStaticGen = staticGenerators.some(g => allDeps[g]);
  if (hasStaticGen && !scripts.start) return true;

  return false;
}

function selectFilesToScan(tree, packageJson) {
  const candidates = new Map();

  if (packageJson?.main) candidates.set(packageJson.main, 0);
  if (packageJson?.bin) {
    if (typeof packageJson.bin === 'string') candidates.set(packageJson.bin, 0);
    else Object.values(packageJson.bin).forEach(v => candidates.set(v, 0));
  }

  const scriptEntries = [];
  if (packageJson?.scripts) {
    for (const script of Object.values(packageJson.scripts)) {
      const matches = script.matchAll(/\b(?:node|ts-node|nodemon|pm2\s+start)\s+([^\s&|]+)/g);
      for (const m of matches) {
        if (m[1] && !m[1].startsWith('-')) scriptEntries.push(m[1]);
      }
    }
  }
  for (const entry of scriptEntries) {
    candidates.set(entry, 0);
    candidates.set(`src/${entry}`, 1);
    candidates.set(`app/${entry}`, 1);
    candidates.set(`bin/${entry}`, 1);
  }

  for (const p of tree) {
    if (!/\.(?:js|ts|mjs|cjs)$/.test(p)) continue;
    if (/\.test\.|\.spec\.|__tests__\/|\.d\.ts$|node_modules|\/dist\/|\/build\/|\.output\//.test(p)) continue;

    let priority = 50;
    const parts = p.split('/').filter(Boolean);
    const depth = parts.length;
    const filename = parts[parts.length - 1] || '';

    if (depth === 1) priority = 5;
    else if (depth === 2) priority = 10;

    if (/^(?:apps|packages)\/[^/]+\/(?:src\/)?(?:server|app|index|main|entry|start|listen|run|cli|api|handler|worker)\./.test(p)) priority = 2;
    else if (/^(?:apps|packages)\/[^/]+\/(?:src|lib|api)\//.test(p)) priority = 8;
    else if (/^(?:apps|packages)\/[^/]+\//.test(p)) priority = 12;
    else if (/^(?:src|app|server|api|lib|bin)\/(?:server|app|index|main|entry|start|listen|run|cli|api|handler|worker)\./.test(p)) priority = 6;
    else if (/^(?:src|app|server|api|lib|bin)\//.test(p)) priority = 10;
    else if (/(?:server|app|index|main|entry|start|listen|run|cli|api|handler|worker|config)\./.test(filename)) priority = 15;
    else if (depth <= 3) priority = 20;
    else priority = 30 + depth;

    if (!candidates.has(p) || candidates.get(p) > priority) {
      candidates.set(p, priority);
    }
  }

  return Array.from(candidates.entries())
    .filter(([p]) => tree.includes(p))
    .sort((a, b) => a[1] - b[1])
    .slice(0, 40)
    .map(([p]) => p);
}

async function scanScripts(packageJson) {
  const findings = [];
  let dynamic = false;
  let hardcoded = false;
  let framework = false;

  if (!packageJson?.scripts) return { findings, dynamic, hardcoded, framework };

  for (const [name, script] of Object.entries(packageJson.scripts)) {
    if (!script) continue;

    if (/process\.env\.PORT|\$PORT|\bPORT=/.test(script)) {
      dynamic = true;
      findings.push({ file: 'package.json', issue: `Script "${name}" uses PORT env var: ${script}` });
    }

    const portMatch = script.match(HARDCODED_PORT_RE);
    if (portMatch) {
      hardcoded = true;
      findings.push({ file: 'package.json', issue: `Script "${name}" has hardcoded port ${portMatch[0]}: ${script}` });
    }

    if (/\b(?:next|nuxt|astro|remix|nitro|wrangler|gatsby|vite)\s+(?:start|dev|serve|preview|pages:dev)/.test(script)) {
      framework = true;
      findings.push({ file: 'package.json', issue: `Script "${name}" uses framework server: ${script}` });
    }
  }

  return { findings, dynamic, hardcoded, framework };
}

async function scanFiles(fileList, files) {
  let foundDynamic = false;
  let foundHardcoded = false;
  let foundFallback = false;
  const findings = [];
  const seen = new Set();

  for (const filePath of fileList) {
    let content;
    try {
      content = await files.get(filePath);
    } catch (e) {
      console.error(`[dynamic-port] Failed to read ${filePath}:`, e);
      continue;
    }
    if (!content) continue;

    const lines = content.split('\n');
    const isNonProd = isNonProductionPath(filePath);

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const trimmed = line.trim();
      if (trimmed.startsWith('//') || trimmed.startsWith('/*') || trimmed.startsWith('*') || trimmed.startsWith('#')) continue;

      for (const pattern of PORT_ENV_PATTERNS) {
        if (pattern.test(line)) {
          foundDynamic = true;
          const key = `${filePath}:${i}:dynamic`;
          if (!seen.has(key)) {
            seen.add(key);
            findings.push({ file: filePath, line: i + 1, issue: 'Uses dynamic port (process.env.PORT or equivalent)' });
          }
        }
      }

      for (const pattern of HARDCODED_PORT_PATTERNS) {
        const match = line.match(pattern);
        if (match) {
          const port = match[1];
          if (isNonProd) {
            const key = `${filePath}:${i}:nonprod:${port}`;
            if (!seen.has(key)) {
              seen.add(key);
              findings.push({ file: filePath, line: i + 1, issue: `Hardcoded port in non-production code: ${port}` });
            }
          } else {
            foundHardcoded = true;
            const key = `${filePath}:${i}:hardcoded:${port}`;
            if (!seen.has(key)) {
              seen.add(key);
              findings.push({ file: filePath, line: i + 1, issue: `Hardcoded port: ${port}` });
            }
          }
        }
      }

      for (const pattern of FALLBACK_PORT_PATTERNS) {
        if (pattern.test(line)) {
          if (isNonProd) {
            const key = `${filePath}:${i}:nonprod-fallback`;
            if (!seen.has(key)) {
              seen.add(key);
              findings.push({ file: filePath, line: i + 1, issue: 'Fallback hardcoded port in non-production code' });
            }
          } else {
            foundFallback = true;
            const key = `${filePath}:${i}:fallback`;
            if (!seen.has(key)) {
              seen.add(key);
              findings.push({ file: filePath, line: i + 1, issue: 'Fallback hardcoded port (process.env.PORT || default)' });
            }
          }
        }
      }
    }
  }

  return { foundDynamic, foundHardcoded, foundFallback, findings };
}

export async function check(context) {
  const { tree, files, packageJson, repoType, owner, repo } = context;

  try {
    if (repoType === 'empty') {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — no server port needed', findings: [] };
    }

    if (looksLikeLibraryOrTool(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or tool detected — no runtime server port needed', findings: [] };
    }

    if (looksLikeStaticSite(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'medium', message: 'Static site detected — no runtime server port needed', findings: [] };
    }

    if (isFrameworkSource(tree, packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Framework source repo — port configuration handled by consumers', findings: [] };
    }

    const filesToScan = selectFilesToScan(tree, packageJson);
    const fileAnalysis = await scanFiles(filesToScan, files);
    const scriptAnalysis = await scanScripts(packageJson);

    let foundDynamic = fileAnalysis.foundDynamic || scriptAnalysis.dynamic;
    let foundHardcoded = fileAnalysis.foundHardcoded || scriptAnalysis.hardcoded;
    let foundFramework = scriptAnalysis.framework;
    const allFindings = [...fileAnalysis.findings, ...scriptAnalysis.findings];

    const workspacePackages = tree.filter(p =>
      p.endsWith('package.json') &&
      p !== 'package.json' &&
      !p.includes('node_modules')
    ).slice(0, 10);

    for (const wp of workspacePackages) {
      try {
        const content = await files.get(wp);
        if (!content) continue;
        const wpPkg = JSON.parse(content);
        const wpAnalysis = await scanScripts(wpPkg);
        if (wpAnalysis.dynamic) foundDynamic = true;
        if (wpAnalysis.hardcoded) foundHardcoded = true;
        if (wpAnalysis.framework) foundFramework = true;
        if (wpAnalysis.findings.length) {
          allFindings.push(...wpAnalysis.findings.map(f => ({ ...f, file: wp })));
        }
      } catch (e) {
        // ignore workspace parse errors
      }
    }

    if (foundHardcoded) {
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded port detected — should use process.env.PORT', findings: allFindings };
    }

    if (foundDynamic) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Dynamic port configuration found (process.env.PORT or equivalent)', findings: allFindings };
    }

    if (fileAnalysis.foundFallback) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Dynamic port configuration found with fallback (process.env.PORT || default)', findings: allFindings };
    }

    if (isFrameworkApp(packageJson) || foundFramework) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Framework app detected — supports dynamic port via PORT env var', findings: allFindings };
    }

    if (isServerFramework(packageJson)) {
      return { checkId, status: 'check-it', confidence: 'medium', message: 'Server framework present but no explicit port configuration found', findings: allFindings };
    }

    if (repoType === 'server' || repoType === 'deployable') {
      return { checkId, status: 'check-it', confidence: 'medium', message: 'Server-related files found but no port configuration detected', findings: allFindings };
    }

    return { checkId, status: 'check-it', confidence: 'low', message: 'No port configuration found in scanned files', findings: allFindings };

  } catch (err) {
    console.error(`[dynamic-port] Error analyzing ${owner}/${repo}:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Analysis error: ${err.message}`, findings: [] };
  }
}
